import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"안전한 모드 찾기","description":"안전한 서비스에서 Fabric 모드를 찾는 방법을 알아보세요.","frontmatter":{"title":"안전한 모드 찾기","description":"안전한 서비스에서 Fabric 모드를 찾는 방법을 알아보세요.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.10/players/finding-mods.md","filePath":"versions/1.21.10/translated/ko_kr/players/finding-mods.md","lastUpdated":1766682904000}`);var a={name:`ko_kr/1.21.10/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">안전한 모드 찾기 <a class="header-anchor" href="#h1" aria-label="Permalink to “안전한 모드 찾기”">​</a></h1><p>먼저, 신뢰는 주관적이므로, 항상 모드를 다운로드 하기 전 직접 판단해야 합니다. 그럼에도, 안전한 모드를 찾는 데 도움이 될 수 있는 여러 가지 방법이 있습니다.</p><h2 id="trustworthy-source" tabindex="-1">1. 신뢰 가능한 것으로 알려진 서비스 사용하기 <a class="header-anchor" href="#trustworthy-source" aria-label="Permalink to “1. 신뢰 가능한 것으로 알려진 서비스 사용하기”">​</a></h2><p>대부분의 모드 개발자는 <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> 또는 CurseForge 에 모드를 게시합니다.</p><p>이러한 서비스에서는 모드가 설명대로 작동하는지, 악성 코드가 포함되어 있지 않은지 검증합니다. 공유되고 있는 악성 모드를 신고할 수도 있습니다. 서비스에서 빠르게 조치할 것입니다.</p><h2 id="with-others" tabindex="-1">2. 다른 것들과 함께 확인하기! <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. 다른 것들과 함께 확인하기!”">​</a></h2><p>신뢰할 수 없는 출처에서 모드를 다운로드하는 경우, 다른 사람들이 같은 출처에서 모드를 다운로드한 적이 있는지, 문제가 없었는지 확인해야 합니다.</p><p>만약 의심이 드신다면, <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord (영어)</a>의 <code>#player-support</code>에서 자유롭게 문의할 수 있습니다.</p><h2 id="avoid-malware" tabindex="-1">3. 일반적인 악성 코드 사이트를 조심하세요! <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. 일반적인 악성 코드 사이트를 조심하세요!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>악성 코드 사이트는 모두에게 분명하지 않을 수도 있습니다. 확실하지 않으시다면, 다른 사람들에게 의견을 물어보거나, 또는 그러한 출처를 완전히 피하고 Modrinth나 CurseForge와 같이 신뢰 가능한 서비스를 사용해야 합니다.</p></div><p>Minecraft의 모드를 제공한다고 주장하지만, 실제론 그냥 악성 코드 사이트거든요. 이러한 사이트는 가급적 피하는 것이 좋습니다.</p><p><a href="https://www.microsoft.com/en-us/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a>와 같은 안티바이러스 소프트웨어를 사용하거나 <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a>에서 다운로드한 모드를 확인할 수 있습니다. 하지만, 이 방법을 전적으로 의지하지 마세요. 가끔 틀리는 경우도 있습니다.</p><p>다시 한 번 더, 의심될 때에는 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord (영어)</a>의 <code>#player-support</code>에서 자유롭게 문의할 수 있습니다.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};